  1	import { Flex, FlexItem, Label, Text, TextVariants, Tooltip } from '@patternfly/react-core';
  2	import { InfoCircleIcon } from '@patternfly/react-icons';
  3	import { ActionsColumn, Table, Tbody, Td, Th, Thead, Tr } from '@patternfly/react-table';
  4	import { TFunction } from 'i18next';
  5	import * as React from 'react';
  6	import { useTranslation } from 'react-i18next';
  7	import { formatActiveSince } from '../../utils/datetime';
  8	import { valueFormat } from '../../utils/format';
  9	import { HealthColorSquare } from './health-color-square';
 10	import {
 11	  getAllHealthItems,
 12	  getItemFilteredLabels,
 13	  getLinks,
 14	  getSeverityColor,
 15	  HealthItem,
 16	  HealthStat,
 17	  HealthSuperKind
 18	} from './health-helper';
 19	import './rule-details.css';
 20	
 21	export interface RuleDetailsProps {
 22	  kind: HealthSuperKind;
 23	  resourceHealth: HealthStat;
 24	}
 25	
 26	// Helper: Get direction from recording rule name
 27	const getDirection = (ruleName?: string): 'src' | 'dst' | undefined => {
 28	  if (!ruleName) return undefined;
 29	  return ruleName.includes(':src:') ? 'src' : ruleName.includes(':dst:') ? 'dst' : undefined;
 30	};
 31	
 32	// Helper: Vertical label/value column
 33	const VerticalField: React.FC<{ label: string; children: React.ReactNode }> = ({ label, children }) => (
 34	  <FlexItem>
 35	    <Flex direction={{ default: 'column' }} gap={{ default: 'gapXs' }}>
 36	      <FlexItem>
 37	        <Text
 38	          component={TextVariants.small}
 39	          style={{
 40	            color: 'var(--pf-t--global--text--color--subtle)'
 41	          }}
 42	        >
 43	          {label}
 44	        </Text>
 45	      </FlexItem>
 46	      <FlexItem>{children}</FlexItem>
 47	    </Flex>
 48	  </FlexItem>
 49	);
 50	
 51	// Helper: Render table row (used for Global table view)
 52	const RuleTableRow: React.FC<{
 53	  item: HealthItem;
 54	  resourceName: string;
 55	  kind: HealthSuperKind;
 56	  t: TFunction;
 57	}> = ({ item, resourceName, kind, t }) => {
 58	  const isAlert = item.state !== 'recording';
 59	  const labels = React.useMemo(() => getItemFilteredLabels(item, resourceName), [item, resourceName]);
 60	  const links = React.useMemo(() => getLinks(t, kind, item, resourceName), [item, kind, resourceName, t]);
 61	  const direction = React.useMemo(() => getDirection(item.ruleName), [item]);
 62	
 63	  return (
 64	    <Tr>
 65	      <Td dataLabel={t('Summary')}>
 66	        <Flex gap={{ default: 'gapXs' }} alignItems={{ default: 'alignItemsCenter' }} flexWrap={{ default: 'nowrap' }}>
 67	          <FlexItem>
 68	            <HealthColorSquare item={item} />
 69	          </FlexItem>
 70	          <FlexItem>
 71	            {item.description ? (
 72	              <Tooltip content={item.description}>
 73	                <span>{item.summary}</span>
 74	              </Tooltip>
 75	            ) : (
 76	              <span>{item.summary}</span>
 77	            )}
 78	          </FlexItem>
 79	        </Flex>
 80	      </Td>
 81	      <Td dataLabel={t('Mode')}>{isAlert ? t('alert') : t('recording')}</Td>
 82	      <Td dataLabel={t('State')}>{isAlert ? item.state : ''}</Td>
 83	      <Td dataLabel={t('Severity')}>
 84	        <Label isCompact color={getSeverityColor(item.severity)}>
 85	          {item.severity}
 86	        </Label>
 87	      </Td>
 88	      <Td dataLabel={t('Active since')}>{item.activeAt ? formatActiveSince(t, item.activeAt) : ''}</Td>
 89	      <Td dataLabel={t('Labels')}>
 90	        {labels.length === 0
 91	          ? ''
 92	          : labels.map(kv => (
 93	              <Label key={kv[0]}>
 94	                {kv[0]}={kv[1]}
 95	              </Label>
 96	            ))}
 97	      </Td>
 98	      <Td dataLabel={t('Value')} className="no-wrap">
 99	        {valueFormat(item.value, 2)} {item.metadata.unit}
100	      </Td>
101	      <Td dataLabel={t('Threshold')}>{item.threshold ? `${item.threshold} ${item.metadata.unit}` : ''}</Td>
102	      <Td dataLabel={t('Direction')}>{direction || ''}</Td>
103	      <Td dataLabel={t('Description')}>{item.description}</Td>
104	      <Td noPadding>
105	        <ActionsColumn
106	          isDisabled={links.length === 0}
107	          items={links.map(l => ({ title: <a href={l.url}>{l.name}</a> }))}
108	        />
109	      </Td>
110	    </Tr>
111	  );
112	};
