114	// Helper: Render card (used for Node/Namespace drawer view)
115	const RuleCard: React.FC<{
116	  item: HealthItem;
117	  resourceName: string;
118	  kind: HealthSuperKind;
119	  t: TFunction;
120	}> = ({ item, resourceName, kind, t }) => {
121	  const isAlert = item.state !== 'recording';
122	  const labels = React.useMemo(() => getItemFilteredLabels(item, resourceName), [item, resourceName]);
123	  const links = React.useMemo(() => getLinks(t, kind, item, resourceName), [item, kind, resourceName, t]);
124	  const direction = React.useMemo(() => getDirection(item.ruleName), [item]);
125	
126	  return (
127	    <div className="rule-details-row">
128	      <Flex direction={{ default: 'column' }} gap={{ default: 'gapSm' }}>
129	        {/* Header with summary and actions */}
130	        <Flex
131	          justifyContent={{ default: 'justifyContentSpaceBetween' }}
132	          alignItems={{ default: 'alignItemsFlexStart' }}
133	        >
134	          <Flex gap={{ default: 'gapXs' }} alignItems={{ default: 'alignItemsFlexStart' }} flex={{ default: 'flex_1' }}>
135	            <FlexItem>
136	              <HealthColorSquare item={item} />
137	            </FlexItem>
138	            <FlexItem flex={{ default: 'flex_1' }}>
139	              <Flex gap={{ default: 'gapXs' }} alignItems={{ default: 'alignItemsCenter' }}>
140	                <FlexItem>{item.summary}</FlexItem>
141	                {item.description && (
142	                  <FlexItem>
143	                    <Tooltip content={item.description}>
144	                      <InfoCircleIcon
145	                        style={{
146	                          color: 'var(--pf-t--global--text--color--subtle)'
147	                        }}
148	                      />
149	                    </Tooltip>
150	                  </FlexItem>
151	                )}
152	              </Flex>
153	            </FlexItem>
154	            <FlexItem>
155	              <ActionsColumn
156	                isDisabled={links.length === 0}
157	                items={links.map(l => ({ title: <a href={l.url}>{l.name}</a> }))}
158	              />
159	            </FlexItem>
160	          </Flex>
161	        </Flex>
162	
163	        {/* Mode, State, Severity, Value, Threshold, Active since, Direction row */}
164	        <Flex gap={{ default: 'gapSm' }}>
165	          <VerticalField label={t('Mode')}>{isAlert ? t('alert') : t('recording')}</VerticalField>
166	          {isAlert && <VerticalField label={t('State')}>{item.state}</VerticalField>}
167	          <VerticalField label={t('Severity')}>
168	            <Label isCompact color={getSeverityColor(item.severity)}>
169	              {item.severity}
170	            </Label>
171	          </VerticalField>
172	          <VerticalField label={t('Value')}>
173	            {valueFormat(item.value, 2)} {item.metadata.unit}
174	          </VerticalField>
175	          {item.threshold && (
176	            <VerticalField label={t('Threshold')}>
177	              {item.threshold} {item.metadata.unit}
178	            </VerticalField>
179	          )}
180	          {item.activeAt && (
181	            <VerticalField label={t('Active since')}>{formatActiveSince(t, item.activeAt)}</VerticalField>
182	          )}
183	          {direction && <VerticalField label={t('Direction')}>{direction}</VerticalField>}
184	        </Flex>
185	
186	        {/* Labels */}
187	        {labels.length > 0 && (
188	          <Flex gap={{ default: 'gapXs' }} flexWrap={{ default: 'wrap' }}>
189	            {labels.map(kv => (
190	              <Label key={kv[0]} isCompact>
191	                {kv[0]}={kv[1]}
192	              </Label>
193	            ))}
194	          </Flex>
195	        )}
196	      </Flex>
197	    </div>
198	  );
199	};
200	
201	export const RuleDetails: React.FC<RuleDetailsProps> = ({ kind, resourceHealth }) => {
202	  const { t } = useTranslation('plugin__netobserv-plugin');
203	
204	  const resourceName = resourceHealth.name || 'Global';
205	  const isGlobal = kind === 'Global';
206	  const allItems = getAllHealthItems(resourceHealth);
207	
208	  // Global view: render table
209	  if (isGlobal) {
210	    return (
211	      <Table
212	        className="rule-details"
213	        data-test-rows-count={allItems.length}
214	        aria-label="Rule details"
215	        variant="compact"
216	      >
217	        <Thead>
218	          <Tr>
219	            <Th>{t('Summary')}</Th>
220	            <Th>{t('Mode')}</Th>
221	            <Th>{t('State')}</Th>
222	            <Th>{t('Severity')}</Th>
223	            <Th className="no-wrap">{t('Active since')}</Th>
224	            <Th>{t('Labels')}</Th>
225	            <Th>{t('Value')}</Th>
226	            <Th>{t('Threshold')}</Th>
227	            <Th>{t('Direction')}</Th>
228	            <Th>{t('Description')}</Th>
229	            <Th screenReaderText="Links" />
230	          </Tr>
231	        </Thead>
232	        <Tbody>
233	          {allItems.map((item, i) => (
234	            <RuleTableRow key={`rule-row-${i}`} item={item} resourceName={resourceName} kind={kind} t={t} />
235	          ))}
236	        </Tbody>
237	      </Table>
238	    );
239	  }
240	
