242	  return (
243	    <Flex direction={{ default: 'column' }} gap={{ default: 'gapMd' }}>
244	      {allItems.map((item, i) => (
245	        <RuleCard key={`rule-card-${i}`} item={item} resourceName={resourceName} kind={kind} t={t} />
246	      ))}
247	    </Flex>
248	  );
249	};

